      "content": "import random

class MarkovChain:
    def __init__(self):
        self.chain = {}

    def train(self, text):
        for i in range(len(text) - 1):
            current_char = text[i]
            next_char = text[i + 1]
            if current_char not in self.chain:
                self.chain[current_char] = []
            self.chain[current_char].append(next_char)

    def generate(self, length):
        if not self.chain:
            return ''
        start_char = random.choice(list(self.chain.keys()))
        result = [start_char]
        current_char = start_char
        while len(result) < length:
            next_chars = self.chain.get(current_char)
            if not next_chars:
                current_char = random.choice(list(self.chain.keys()))
                continue
            next_char = random.choice(next_chars)
            result.append(next_char)
            current_char = next_char
        return ''.join(result[:length])
